"use strict";(self.webpackChunktemporal_documentation=self.webpackChunktemporal_documentation||[]).push([["4310"],{4782(e){e.exports=JSON.parse('{"tag":{"label":"Nexus","permalink":"/tags/nexus","allTagsPath":"/tags","count":22,"items":[{"id":"encyclopedia/nexus-use-cases","title":"Common use cases for Temporal Nexus","description":"Common use cases for Temporal Nexus","permalink":"/nexus/use-cases"},{"id":"encyclopedia/nexus-error-handling","title":"Error handling - Temporal Nexus","description":"Learn about error handling for Temporal Nexus.","permalink":"/nexus/error-handling"},{"id":"encyclopedia/nexus-execution-debugging","title":"Execution debugging - Temporal Nexus","description":"Learn about execution debugging in Temporal Nexus.","permalink":"/nexus/execution-debugging"},{"id":"cloud/nexus/latency-availability","title":"Latency and Availability - Temporal Nexus","description":"Learn about Nexus latency and availability","permalink":"/cloud/nexus/latency-availability"},{"id":"cloud/nexus/limits","title":"Limits - Temporal Nexus","description":"Learn about Nexus limits including rate limits, the maximum number of Endpoints, and handler request timeouts.","permalink":"/cloud/nexus/limits"},{"id":"cloud/nexus/index","title":"Nexus","description":"Discover Temporal Nexus, a powerful feature for connecting durable executions across team, namespace, region, and cloud boundaries. Nexus also enables each team to have their own namespace for improved security, troubleshooting, and blast radius isolation.","permalink":"/cloud/nexus"},{"id":"encyclopedia/nexus-endpoints","title":"Nexus endpoints","description":"Nexus Endpoints are reverse proxies that connect Nexus callers and handlers forwarding Nexus requests to an upstream target Namespace and Task Queue that a Worker is polling.","permalink":"/nexus/endpoints"},{"id":"encyclopedia/nexus-metrics","title":"Nexus metrics","description":"Learn about available metrics emitted by Temporal Nexus.","permalink":"/nexus/metrics"},{"id":"encyclopedia/nexus-operations","title":"Nexus operations","description":"Learn about the Nexus Operation lifecycle, execution semantics, and automatic retries for reliable execution.","permalink":"/nexus/operations"},{"id":"encyclopedia/nexus-registry","title":"Nexus Registry","description":"Use the Nexus Registry to manage Nexus Endpoints.","permalink":"/nexus/registry"},{"id":"encyclopedia/nexus-services","title":"Nexus services","description":"Nexus Services are named collections of arbitrary-duration Nexus Operations that provide a microservice contract suitable for sharing across team boundaries.","permalink":"/nexus/services"},{"id":"cloud/nexus/observability","title":"Observability - Temporal Nexus","description":"Learn about integrated observability in Temporal Nexus including cloud metrics and audit log streaming.","permalink":"/cloud/nexus/observability"},{"id":"cloud/nexus/pricing","title":"Pricing for Temporal Nexus","description":"Learn about the pricing structure for using Nexus.","permalink":"/cloud/nexus/pricing"},{"id":"cloud/nexus/security","title":"Security - Temporal Nexus","description":"Learn about security in Temporal Nexus","permalink":"/cloud/nexus/security"},{"id":"encyclopedia/nexus-security","title":"Security in Temporal Nexus","description":"Explore the security aspects of Temporal Nexus, including managing Nexus Endpoints, runtime access control, secure routing, and payload encryption to ensure safe and reliable cross-namespace operations.","permalink":"/nexus/security"},{"id":"encyclopedia/nexus","title":"Temporal Nexus","description":"Temporal Nexus is a feature of the Temporal platform designed to connect durable executions across team, namespace, region, and cloud boundaries. It promotes a more modular architecture for sharing a subset of your team\'s capabilities via well-defined microservice contracts for other teams to use, that abstract underlying Temporal primitives, like Workflows, or execute arbitrary code.","permalink":"/nexus"},{"id":"develop/dotnet/nexus","title":"Temporal Nexus - .NET SDK feature guide","description":"Use Temporal Nexus within the .NET SDK to connect Durable Executions within and across Namespaces using a Nexus Endpoint, a Nexus Service contract, and Nexus Operations.","permalink":"/develop/dotnet/nexus"},{"id":"develop/go/nexus","title":"Temporal Nexus - Go SDK feature guide","description":"Use Temporal Nexus within the Go SDK to connect durable executions within and across Namespaces using a Nexus Endpoint, a Nexus Service contract, and Nexus Operations.","permalink":"/develop/go/nexus"},{"id":"develop/java/nexus","title":"Temporal Nexus - Java SDK feature guide","description":"Use Temporal Nexus within the Java SDK to connect Durable Executions within and across Namespaces using a Nexus Endpoint, a Nexus Service contract, and Nexus Operations.","permalink":"/develop/java/nexus"},{"id":"develop/python/nexus","title":"Temporal Nexus - Python SDK feature guide","description":"Use Temporal Nexus within the Python SDK to connect Durable Executions within and across Namespaces using a Nexus Endpoint, a Nexus Service contract, and Nexus Operations.","permalink":"/develop/python/nexus"},{"id":"evaluate/development-production-features/nexus","title":"Temporal Nexus - Temporal feature","description":"Temporal Nexus enables durable execution across team and namespace boundaries and promotes a modular architecture that enables each team to have its own namespace for improved security, troubleshooting, and blast radius isolation.","permalink":"/evaluate/nexus"},{"id":"develop/typescript/nexus","title":"Temporal Nexus - TypeScript SDK feature guide","description":"Use Temporal Nexus within the TypeScript SDK to connect Durable Executions within and across Namespaces using a Nexus Endpoint, a Nexus Service contract, and Nexus Operations.","permalink":"/develop/typescript/nexus"}],"unlisted":false}}')}}]);